// ====================================================================
// FERRY PROXIMITY DETECTION - Clean Version
// ====================================================================
// What this does: Alerts you when ferries come within X meters of buildings
// How it works: Calculates distance between ferry GPS positions and buildings
// ====================================================================

// ====================================================================
// STEP 1: CREATE TABLES (Run these commands once)
// ====================================================================

// Table to store your reference locations/points of interest
.create table ReferenceLocation (
    LocationId: string,
    LocationName: string,
    Latitude: real,
    Longitude: real,
    ProximityThreshold: real  // Alert when ferry is within this many meters
)

// Table to store alerts when ferries get close
.create table ProximityAlerts (
    timestamp: datetime,
    ferry_name: string,
    ferry_destination: string,
    LocationId: string,
    LocationName: string,
    Distance: real,
    FerryLatitude: real,
    FerryLongitude: real,
    LocationLatitude: real,
    LocationLongitude: real,
    Alert: string
)

// ====================================================================
// STEP 2: ADD YOUR BUILDINGS (Run once, then add more as needed)
// ====================================================================

// Clear existing reference locations (run this first if you need to start fresh)
.clear table ReferenceLocation data

// Then add your reference location (note: first line is header, will be skipped automatically)
.ingest inline into table ReferenceLocation with (ignoreFirstRecord=true) <|
LocationId,LocationName,Latitude,Longitude,ProximityThreshold
LOC001,Reference Point,-33.85485,151.22575,150

// ====================================================================
// STEP 3: CREATE FUNCTIONS (Run once)
// ====================================================================

// Function 1: Get latest position of each ferry
.create-or-alter function GetLatestFerryPositions() {
    SydneyFerries
    | summarize latestTimestamp=max(timestamp) by ferry_name
    | join kind=inner (
        SydneyFerries
        | project ferry_name, ferry_lat, ferry_long, ferry_destination, timestamp
    ) on ferry_name, $left.latestTimestamp == $right.timestamp
    | where timestamp > ago(3h)
    | project ferry_name, ferry_lat, ferry_long, ferry_destination, timestamp
}

// Function 2: Calculate distance between two GPS points (in meters)
// Uses Haversine formula - standard way to calculate distance on Earth's curved surface
.create-or-alter function CalculateDistance(lat1:real, lon1:real, lat2:real, lon2:real) {
    let R = 6371000.0;  // Earth's radius in meters
    let dLat = radians(lat2 - lat1);
    let dLon = radians(lon2 - lon1);
    let a = sin(dLat/2) * sin(dLat/2) + 
            cos(radians(lat1)) * cos(radians(lat2)) * 
            sin(dLon/2) * sin(dLon/2);
    let c = 2 * atan2(sqrt(a), sqrt(1-a));
    R * c  // Returns distance in meters
}

// Function 3: Detect ferries within proximity threshold
.create-or-alter function DetectProximity() {
    GetLatestFerryPositions()
    | extend dummy = 1
    | join kind=inner (ReferenceLocation | extend dummy = 1) on dummy  // Cross join: every ferry with every location
    | project-away dummy, dummy1
    | extend Distance = CalculateDistance(ferry_lat, ferry_long, Latitude, Longitude)
    | where Distance <= ProximityThreshold  // Only keep alerts within threshold
    | project 
        timestamp,
        ferry_name,
        ferry_destination,
        LocationId,
        LocationName,
        Distance = round(Distance, 2),
        FerryLatitude = ferry_lat,
        FerryLongitude = ferry_long,
        LocationLatitude = Latitude,
        LocationLongitude = Longitude,
        Alert = strcat(ferry_name, " (→ ", ferry_destination, ") is ", round(Distance, 2), "m from ", LocationName)
}

// ====================================================================
// STEP 4: USE THE SYSTEM - Run these queries anytime
// ====================================================================

// See current ferry positions
GetLatestFerryPositions()

// Check for proximity alerts right now
DetectProximity()

// See all distances (helpful for debugging)
GetLatestFerryPositions()
| extend dummy = 1
| join kind=inner (ReferenceLocation | extend dummy = 1) on dummy
| project-away dummy, dummy1
| extend Distance = CalculateDistance(ferry_lat, ferry_long, Latitude, Longitude)
| project ferry_name, ferry_destination, LocationName, Distance = round(Distance, 2)
| order by Distance asc

// ====================================================================
// STEP 5: MANUAL ALERT SAVING (Run periodically to save alerts)
// ====================================================================

// Option A: Run this query manually or schedule it (e.g., every 30 seconds)
// to save current alerts to the ProximityAlerts table
.set-or-append ProximityAlerts <|
DetectProximity()

// Option B: Save only NEW alerts (checks last 30 seconds of ferry data)
.set-or-append ProximityAlerts <|
SydneyFerries
| where timestamp > ago(30s)
| extend dummy = 1
| join kind=inner (ReferenceLocation | extend dummy = 1) on dummy
| project-away dummy, dummy1
| extend Distance = CalculateDistance(ferry_lat, ferry_long, Latitude, Longitude)
| where Distance <= ProximityThreshold
| project 
    timestamp,
    ferry_name,
    ferry_destination,
    LocationId,
    LocationName,
    Distance = round(Distance, 2),
    FerryLatitude = ferry_lat,
    FerryLongitude = ferry_long,
    LocationLatitude = Latitude,
    LocationLongitude = Longitude,
    Alert = strcat(ferry_name, " (→ ", ferry_destination, ") is ", round(Distance, 2), "m from ", LocationName)

// View saved alerts from last hour
ProximityAlerts
| where timestamp > ago(1h)
| order by timestamp desc

// ====================================================================
// STEP 6: REAL-TIME MONITORING (Recommended approach)
// ====================================================================

// BEST OPTION: Direct query for live alerts
// This works immediately and calculates in real-time
// Use this in Power BI (set auto-refresh to 30s) or Power Automate
DetectProximity()

// Alternative: Query with alert filtering
// Only show ferries that are currently within threshold
GetLatestFerryPositions()
| extend TargetLat = -33.85485, TargetLon = 151.22575, Threshold = 150.0
| extend Distance = CalculateDistance(ferry_lat, ferry_long, TargetLat, TargetLon)
| where Distance <= Threshold
| project 
    timestamp,
    ferry_name,
    ferry_destination,
    Distance = round(Distance, 2),
    Alert = strcat(ferry_name, " (→ ", ferry_destination, ") is ", round(Distance, 2), "m from Reference Point")
| order by Distance asc

// ====================================================================
// STEP 7: SCHEDULED MONITORING (For Email/Teams notifications)
// ====================================================================

// Run this query from Power Automate every 30 seconds
// If it returns rows, send notification
DetectProximity()
| project 
    ferry_name,
    ferry_destination,
    LocationName,
    Distance,
    Alert,
    timestamp

// Example for checking specific ferry
GetLatestFerryPositions()
| where ferry_name == "Manly Ferry"
| extend TargetLat = -33.85485, TargetLon = 151.22575
| extend Distance = CalculateDistance(ferry_lat, ferry_long, TargetLat, TargetLon)
| extend InProximity = iff(Distance <= 150, "YES - ALERT!", "No")
| project ferry_name, ferry_destination, Distance = round(Distance, 2), InProximity, timestamp
